function togglePasswordLogin(){const field=document.getElementById("password"),icon=document.getElementById("password-login-icon");"password"===field.type?(field.type="text",icon.classList.remove("fa-eye"),icon.classList.add("fa-eye-slash")):(field.type="password",icon.classList.remove("fa-eye-slash"),icon.classList.add("fa-eye"))}document.addEventListener("DOMContentLoaded",(function(){const form=document.querySelector('form[action*="action=login"]'),btn=document.querySelector(".btn-login");form&&btn&&form.addEventListener("submit",(function(){btn.disabled=!0,btn.innerHTML='<span class="spinner-border spinner-border-sm mr-2" role="status" aria-hidden="true"></span> Signing in...'}))}));